<template>
  <div class="card mx-3">
    <div class="row">
      <div class="col-lg-3 col-sm-12">
        <img
          :src="getLogo"
          class="card-img-top"
          :class="winWidth < 992 ? 'p-4' : 'm-4'"
          :alt="work.name"
        />
      </div>
      <div class="col-lg-9 col-sm-12">
        <div class="card-body">
          <h5 class="card-title">{{ work.name }}</h5>
          <div class="row">
            <div class="col">
              <h6 class="text-center card-subtitle text-muted">
                {{ work.location }}
              </h6>
            </div>
            <div class="col">
              <h6 class="text-center card-subtitle text-muted">
                {{ work.years }}
              </h6>
            </div>
          </div>

          <p class="card-text">
            <strong>{{ $t("Position") }}:</strong> {{ getPosition }}<br />
            <strong>{{ $t("Duties") }}:</strong> {{ getDuties }}<br />
            <strong>{{ $t("Projects") }}:</strong>
          </p>
          <ul class="list">
            <li v-for="p in work.projects" :key="p">
              {{ p[currentLang] }}
            </li>
          </ul>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { ref, onMounted, onUnmounted, computed } from "vue";
export default {
  name: "WorkCard",
  props: ["work"],
  computed: {
    getPosition() {
      return this.work.position[this.currentLang];
    },
    getDuties() {
      return this.work.duties[this.currentLang];
    },
    getLogo() {
      return require(`@/assets/${this.work.logo}`);
    },
    currentLang() {
      return this.$i18n.locale;
    },
  },
  setup() {
    let windowWidth = ref(window.innerWidth);

    const onWidthChange = () => (windowWidth.value = window.innerWidth);
    onMounted(() => window.addEventListener("resize", onWidthChange));
    onUnmounted(() => window.removeEventListener("resize", onWidthChange));

    const breakpoint = computed(() => {
      if (windowWidth.value < 576) return "xs";
      else if (windowWidth.value >= 576 && windowWidth.value < 768) return "sm";
      else if (windowWidth.value >= 768 && windowWidth.value < 992) return "md";
      else if (windowWidth.value >= 992 && windowWidth.value < 1200)
        return "lg";
      else if (windowWidth.value >= 1200 && windowWidth.value < 1400)
        return "xl";
      else return "xxl";
    });
    const winWidth = computed(() => windowWidth.value);

    return { winWidth, breakpoint };
  },
};
</script>
